<?php
declare(strict_types=1);namespace App\Services\ControlEscaneres\Shared;use App\Domain\ControlEscaneres\ScannerStatus;use App\Exceptions\ControlEscaneres\InvalidScannerStatusException;
final class ScannerStateMachine implements ScannerStateMachineInterface{private const MAP=['disponible'=>['entregado','mantenimiento','pendiente_reparacion','baja_definitiva','extraviado'],'entregado'=>['disponible','pendiente_reparacion','extraviado'],'mantenimiento'=>['disponible','pendiente_reparacion','baja_definitiva'],'pendiente_reparacion'=>['mantenimiento','disponible','baja_definitiva'],'baja_definitiva'=>[],'extraviado'=>['disponible','baja_definitiva']];public function canTransition(ScannerStatus$f,ScannerStatus$t):bool{return in_array($t->value,self::MAP[$f->value]??[],true);}public function assertTransition(ScannerStatus$f,ScannerStatus$t):void{if(!$this->canTransition($f,$t))throw new InvalidScannerStatusException('Transición de estado no permitida.');}public function allowedTransitionsFrom(ScannerStatus$f):array{return array_map(fn($v)=>new ScannerStatus($v),self::MAP[$f->value]??[]);}}
